import{_ as e,o as s,c as o,a2 as n}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Fronteras modulos y paquetes","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/08-fronteras-modulos-y-paquetes.md","filePath":"full-stack/arquitectura/clean-architecture/08-fronteras-modulos-y-paquetes.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/clean-architecture/08-fronteras-modulos-y-paquetes.md"};function i(r,a,l,p,d,c){return s(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="fronteras-modulos-y-paquetes" tabindex="-1">Fronteras modulos y paquetes <a class="header-anchor" href="#fronteras-modulos-y-paquetes" aria-label="Permalink to &quot;Fronteras modulos y paquetes&quot;">​</a></h1><p>Una frontera arquitectonica marca que puede conocer una parte del sistema y que no.</p><h2 id="frontera-por-modulo" tabindex="-1">Frontera por modulo <a class="header-anchor" href="#frontera-por-modulo" aria-label="Permalink to &quot;Frontera por modulo&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>modules/</span></span>
<span class="line"><span>  billing/</span></span>
<span class="line"><span>  identity/</span></span>
<span class="line"><span>  catalog/</span></span>
<span class="line"><span>  orders/</span></span></code></pre></div><p>Cada modulo deberia tener lenguaje, casos de uso y reglas propias.</p><h2 id="frontera-por-capa" tabindex="-1">Frontera por capa <a class="header-anchor" href="#frontera-por-capa" aria-label="Permalink to &quot;Frontera por capa&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders/</span></span>
<span class="line"><span>  domain/</span></span>
<span class="line"><span>  application/</span></span>
<span class="line"><span>  infrastructure/</span></span>
<span class="line"><span>  presentation/</span></span></code></pre></div><p>Esta estructura ayuda a ver dependencias dentro de un modulo.</p><h2 id="evitar-el-modulo-compartido-gigante" tabindex="-1">Evitar el modulo compartido gigante <a class="header-anchor" href="#evitar-el-modulo-compartido-gigante" aria-label="Permalink to &quot;Evitar el modulo compartido gigante&quot;">​</a></h2><p><code>shared</code>, <code>common</code> o <code>utils</code> pueden convertirse en un cajon sin criterio.</p><p>Usalos para tipos realmente transversales, utilidades puras, errores base y primitivas comunes estables.</p><p>Evitalos para reglas de negocio, servicios ambiguos, DTOs de cualquier modulo o dependencias que solo usa una feature.</p><h2 id="contratos-entre-modulos" tabindex="-1">Contratos entre modulos <a class="header-anchor" href="#contratos-entre-modulos" aria-label="Permalink to &quot;Contratos entre modulos&quot;">​</a></h2><p>Los modulos no deberian tocar tablas internas de otros modulos directamente. Es mejor comunicarse mediante:</p><ul><li>Casos de uso publicos.</li><li>Eventos de dominio.</li><li>APIs internas.</li><li>Contratos de lectura.</li></ul><h2 id="dependencias-permitidas" tabindex="-1">Dependencias permitidas <a class="header-anchor" href="#dependencias-permitidas" aria-label="Permalink to &quot;Dependencias permitidas&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders/application -&gt; orders/domain</span></span>
<span class="line"><span>orders/infrastructure -&gt; orders/application</span></span>
<span class="line"><span>billing/application -&gt; billing/domain</span></span></code></pre></div><p>Dependencias sospechosas:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders/domain -&gt; billing/infrastructure</span></span>
<span class="line"><span>catalog/application -&gt; orders/database-model</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Cada modulo tiene una responsabilidad clara.</li><li>Las dependencias cruzadas son visibles.</li><li>No hay acceso directo a detalles internos de otros modulos.</li><li>Las utilidades compartidas no contienen negocio oculto.</li><li>Los nombres reflejan conceptos del dominio.</li></ul>`,21)])])}const h=e(t,[["render",i]]);export{m as __pageData,h as default};
